97	// ExecutionCleanupLivenessProbe decides whether a cleanup candidate should be
98	// preserved because it is still live.
99	type ExecutionCleanupLivenessProbe interface {
100		IsLive(meta ExecutionCleanupMetadata, runState *RunState, now time.Time) (bool, string)
101	}
102	
103	// defaultExecutionCleanupLivenessProbe preserves preserved metadata, a temp
104	// execution directory referenced by the live run-state file, or a candidate
105	// with an unexpired liveness marker. Tests can override the probe to model
106	// more specific host behavior.
107	type defaultExecutionCleanupLivenessProbe struct{}
108	
109	func (defaultExecutionCleanupLivenessProbe) IsLive(meta ExecutionCleanupMetadata, runState *RunState, now time.Time) (bool, string) {
110		if meta.Preserved {
111			return true, "preserved metadata"
112		}
113		if meta.ActiveCandidateCycle {
114			return true, "active candidate cycle"
115		}
116		if runState != nil {
117			if meta.WorktreePath != "" && filepath.Clean(runState.WorktreePath) == filepath.Clean(meta.WorktreePath) {
118				return true, "matched live run-state"
119			}
120			if meta.AttemptID != "" && runState.AttemptID == meta.AttemptID {
121				return true, "matched live run-state"
122			}
123		}
124		if meta.Liveness != nil {
125			if !meta.Liveness.ExpiresAt.IsZero() && now.Before(meta.Liveness.ExpiresAt) {
126				return true, "unexpired liveness"
127			}
128			if !meta.Liveness.RefreshedAt.IsZero() && now.Sub(meta.Liveness.RefreshedAt) <= 2*time.Minute {
129				return true, "fresh liveness"
130			}
131		}
132		return false, "stale liveness"
133	}
