146	// NewExecutionCleanupManager constructs a cleanup manager with the default
147	// DDx temp worktree root and the default liveness probe.
148	func NewExecutionCleanupManager(projectRoot string, gitOps GitOps) *ExecutionCleanupManager {
149		return &ExecutionCleanupManager{
150			ProjectRoot: projectRoot,
151			TempRoot:    executionCleanupTempRoot(projectRoot),
152			GitOps:      gitOps,
153			Now:         time.Now,
154			Probe:       defaultExecutionCleanupLivenessProbe{},
