158	// Cleanup scans the configured DDx temp worktree root, consults the project
159	// run-state file and git worktree registry, and conservatively removes stale
160	// DDx-owned temp resources.
161	func (m *ExecutionCleanupManager) Cleanup(ctx context.Context) (ExecutionCleanupSummary, error) {
162		_ = ctx
163	
164		summary := ExecutionCleanupSummary{
165			ProjectRoot: m.ProjectRoot,
166			TempRoot:    m.tempRoot(),
167		}
168		if summary.TempRoot == "" {
169			summary.TempRoot = executionCleanupTempRoot(m.ProjectRoot)
170		}
171		if summary.TempRoot == "" {
172			return summary, errors.New("execution cleanup: temp root is empty")
173		}
174		if m.ProjectRoot == "" {
175			return summary, errors.New("execution cleanup: project root is empty")
176		}
177		now := time.Now
178		if m.Now != nil {
179			now = m.Now
180		}
181		probe := m.Probe
182		if probe == nil {
183			probe = defaultExecutionCleanupLivenessProbe{}
184		}
185	
186		registered := map[string]struct{}{}
187		liveRunStates := map[string]struct{}{}
188		if m.GitOps != nil {
189			paths, err := m.GitOps.WorktreeList(m.ProjectRoot)
190			if err != nil {
191				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
192					Path:    m.ProjectRoot,
193					Class:   "git_worktree_list",
194					Message: err.Error(),
195				})
196			} else {
197				for _, p := range paths {
198					registered[filepath.Clean(p)] = struct{}{}
199				}
200			}
201		}
202	
203		runStates, runStateErr := ReadRunStates(m.ProjectRoot)
204		if runStateErr != nil {
205			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
206				Path:    runStateDirPath(m.ProjectRoot),
207				Class:   "run_state_read",
208				Message: runStateErr.Error(),
209			})
210		}
211	
212		entries, err := os.ReadDir(summary.TempRoot)
213		if err != nil {
214			return summary, fmt.Errorf("execution cleanup: read temp root: %w", err)
215		}
216		for _, entry := range entries {
217			if !entry.IsDir() {
218				continue
219			}
220			if !strings.HasPrefix(entry.Name(), ExecuteBeadWtPrefix) {
221				continue
222			}
223			summary.ScannedTempDirs++
224			path := filepath.Join(summary.TempRoot, entry.Name())
225	
226			meta, metaErr := ReadExecutionCleanupMetadata(path)
227			missingMetadata := false
228			if metaErr != nil {
229				if errors.Is(metaErr, os.ErrNotExist) {
230					missingMetadata = true
231					meta = ExecutionCleanupMetadata{
232						ProjectRoot:  m.ProjectRoot,
233						WorktreePath: path,
234					}
235				} else {
236					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
237						Path:    path,
238						Class:   "metadata_read",
239						Message: metaErr.Error(),
240					})
241					continue
242				}
243			}
244			if meta.ProjectRoot != "" && filepath.Clean(meta.ProjectRoot) != filepath.Clean(m.ProjectRoot) {
245				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
246					Path:    path,
247					Class:   "ownership_mismatch",
248					Message: fmt.Sprintf("metadata project_root=%s does not match manager project_root=%s", meta.ProjectRoot, m.ProjectRoot),
249				})
250				continue
251			}
252	
253			matchedRunState := matchingRunStateForMeta(runStates, meta)
254			live, reason := probe.IsLive(meta, matchedRunState, now())
255			if live {
256				if matchedRunState != nil {
257					liveRunStates[runStateLiveKey(*matchedRunState)] = struct{}{}
258				}
259				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
260					Path:    path,
261					Class:   "preserved_temp_dir",
262					Message: reason,
263				})
264				continue
265			}
266	
267			if _, ok := registered[filepath.Clean(path)]; ok {
268				if missingMetadata {
269					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
270						Path:    path,
271						Class:   "registered_missing_metadata",
272						Message: "registered DDx worktree has no cleanup metadata; preserving",
273					})
274					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
275						Path:    path,
276						Class:   "preserved_registered_missing_metadata",
277						Message: "registered worktree without cleanup metadata",
278					})
279					continue
280				}
281				if m.GitOps == nil {
282					summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
283						Path:     path,
284						Class:    "registered_worktree",
285						Message:  "no git ops available to remove registered worktree",
286						Blocking: true,
287					})
288					continue
289				}
290				reclaimedBytes, reclaimedInodes, measureErr := measureTree(path)
291				if measureErr != nil {
292					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
293						Path:    path,
294						Class:   "measure_tree",
295						Message: measureErr.Error(),
296					})
297				}
298				if !m.DryRun {
299					if err := m.GitOps.WorktreeRemove(m.ProjectRoot, path); err != nil {
300						summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
301							Path:     path,
302							Class:    "registered_worktree_remove",
303							Message:  err.Error(),
304							Blocking: true,
305						})
306						continue
307					}
308				}
309				summary.RemovedRegisteredWorktrees++
310				summary.BytesReclaimed += reclaimedBytes
311				summary.InodesReclaimed += reclaimedInodes
312				class := "removed_registered_worktree"
313				if m.DryRun {
314					class = "would_remove_registered_worktree"
315				}
316				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
317					Path:    path,
318					Class:   class,
319					Message: reason,
320					Bytes:   reclaimedBytes,
321					Inodes:  reclaimedInodes,
322				})
323				continue
324			}
325	
326			reclaimedBytes, reclaimedInodes, measureErr := measureTree(path)
327			if measureErr != nil {
328				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
329					Path:    path,
330					Class:   "measure_tree",
331					Message: measureErr.Error(),
332				})
333			}
334			if !m.DryRun {
335				if err := os.RemoveAll(path); err != nil {
336					summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
337						Path:     path,
338						Class:    "unregistered_temp_dir_remove",
339						Message:  err.Error(),
340						Blocking: false,
341					})
342					continue
343				}
344			}
345			summary.RemovedUnregisteredTempDirs++
346			summary.BytesReclaimed += reclaimedBytes
347			summary.InodesReclaimed += reclaimedInodes
348			class := "removed_unregistered_temp_dir"
349			if m.DryRun {
350				class = "would_remove_unregistered_temp_dir"
351			}
352			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
353				Path:    path,
354				Class:   class,
355				Message: reason,
356				Bytes:   reclaimedBytes,
357				Inodes:  reclaimedInodes,
358			})
359		}
360	
361		if m.GitOps != nil && summary.RemovedRegisteredWorktrees > 0 && !m.DryRun {
362			if err := m.GitOps.WorktreePrune(m.ProjectRoot); err != nil {
363				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
364					Path:    m.ProjectRoot,
365					Class:   "worktree_prune",
366					Message: err.Error(),
367				})
368			}
369		}
370	
371		// Stale run-state files are removed when they point at an execution
372		// resource that is no longer live.
373		for _, state := range runStates {
374			if _, ok := liveRunStates[runStateLiveKey(state)]; ok {
375				continue
376			}
377			if runStateWorktreeStillExists(state) {
378				continue
379			}
380			if removed, bytes := m.removeStaleRunState(state, &summary); removed {
381				summary.RemovedRunStateFiles++
382				summary.BytesReclaimed += bytes
383				summary.InodesReclaimed++
384			}
385		}
386	
387		summary.ScannedEvidenceDirs += scanCompleteEvidenceDirs(m.ProjectRoot, ExecuteBeadArtifactDir, "manifest.json", "result.json", &summary)
388		summary.ScannedEvidenceDirs += scanCompleteEvidenceDirs(m.ProjectRoot, ".ddx/runs", "record.json", "", &summary)
389	
390		return summary, nil
391	}
