393	func matchingRunStateForMeta(states []RunState, meta ExecutionCleanupMetadata) *RunState {
394		for i := range states {
395			state := states[i]
396			if meta.AttemptID != "" && state.AttemptID == meta.AttemptID {
397				return &states[i]
398			}
399			if meta.WorktreePath != "" && state.WorktreePath != "" && filepath.Clean(state.WorktreePath) == filepath.Clean(meta.WorktreePath) {
400				return &states[i]
401			}
402		}
403		return nil
404	}
405	
406	func runStateLiveKey(state RunState) string {
407		if state.AttemptID != "" {
408			return "attempt:" + state.AttemptID
409		}
410		if state.WorktreePath != "" {
411			return "path:" + filepath.Clean(state.WorktreePath)
412		}
413		return "bead:" + state.BeadID
414	}
415	
416	func runStateWorktreeStillExists(state RunState) bool {
417		if state.WorktreePath == "" {
418			return false
419		}
420		_, err := os.Stat(state.WorktreePath)
421		return err == nil
422	}
