424	func (m *ExecutionCleanupManager) removeStaleRunState(state RunState, summary *ExecutionCleanupSummary) (bool, int64) {
425		path := runStatePath(m.ProjectRoot)
426		clear := func() error {
427			return ClearRunState(m.ProjectRoot)
428		}
429		if state.AttemptID != "" {
430			if attemptPath, err := runStateAttemptPath(m.ProjectRoot, state.AttemptID); err == nil {
431				path = attemptPath
432				clear = func() error {
433					return ClearRunStateAttempt(m.ProjectRoot, state.AttemptID)
434				}
435			}
436		}
437	
438		var bytes int64
439		present := false
440		if info, statErr := os.Stat(path); statErr == nil {
441			present = true
442			bytes = info.Size()
443		} else if os.IsNotExist(statErr) && path != runStatePath(m.ProjectRoot) {
444			path = runStatePath(m.ProjectRoot)
445			if info, legacyErr := os.Stat(path); legacyErr == nil {
446				present = true
447				bytes = info.Size()
448				clear = func() error {
449					return ClearRunState(m.ProjectRoot)
450				}
451			}
452		}
453		if !m.DryRun {
454			if err := clear(); err != nil {
455				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
456					Path:    path,
457					Class:   "run_state_clear",
458					Message: err.Error(),
459				})
460			}
461		}
462		if !present {
463			return false, 0
464		}
465		class := "removed_run_state"
466		if m.DryRun {
467			class = "would_remove_run_state"
468		}
469		summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
470			Path:    path,
471			Class:   class,
472			Message: "stale run-state",
473			Bytes:   bytes,
474			Inodes:  1,
475		})
476		return true, bytes
477	}
