489	func executionCleanupTempRoot(projectRoot string) string {
490		base := config.ExecutionWorktreeRoot(projectRoot)
491		if base == "" {
492			base = filepath.Join(os.TempDir(), ExecuteBeadTmpSubdir)
493		}
494		return base
