497	// WriteExecutionCleanupMetadata writes the ownership metadata used by the
498	// cleanup manager for tests and future call sites.
499	func WriteExecutionCleanupMetadata(dir string, meta ExecutionCleanupMetadata) error {
500		if dir == "" {
501			return errors.New("write execution cleanup metadata: dir is empty")
502		}
503		data, err := json.MarshalIndent(meta, "", "  ")
504		if err != nil {
505			return fmt.Errorf("write execution cleanup metadata: marshal: %w", err)
506		}
507		data = append(data, '\n')
508		if err := os.MkdirAll(dir, 0o755); err != nil {
509			return fmt.Errorf("write execution cleanup metadata: mkdir: %w", err)
510		}
511		return os.WriteFile(filepath.Join(dir, ExecutionCleanupMetadataFileName), data, 0o644)
512	}
513	
514	// ReadExecutionCleanupMetadata reads the cleanup metadata file from dir.
515	func ReadExecutionCleanupMetadata(dir string) (ExecutionCleanupMetadata, error) {
516		data, err := os.ReadFile(filepath.Join(dir, ExecutionCleanupMetadataFileName))
517		if err != nil {
518			return ExecutionCleanupMetadata{}, err
519		}
520		var meta ExecutionCleanupMetadata
521		if err := json.Unmarshal(data, &meta); err != nil {
522			return ExecutionCleanupMetadata{}, fmt.Errorf("read execution cleanup metadata: parse: %w", err)
523		}
524		return meta, nil
525	}
