527	func measureTree(path string) (bytes int64, inodes int64, err error) {
528		info, err := os.Lstat(path)
529		if err != nil {
530			return 0, 0, err
531		}
532		if !info.IsDir() {
533			return info.Size(), 1, nil
534		}
535		err = filepath.WalkDir(path, func(p string, d os.DirEntry, walkErr error) error {
536			if walkErr != nil {
537				return walkErr
538			}
539			inodes++
540			fi, statErr := d.Info()
541			if statErr != nil {
542				return statErr
543			}
544			bytes += fi.Size()
545			return nil
546		})
547		return bytes, inodes, err
548	}
