550	func scanCompleteEvidenceDirs(projectRoot, rootRel string, primaryFile, secondaryFile string, summary *ExecutionCleanupSummary) int {
551		root := filepath.Join(projectRoot, filepath.FromSlash(rootRel))
552		entries, err := os.ReadDir(root)
553		if err != nil {
554			return 0
555		}
556		count := 0
557		for _, entry := range entries {
558			if !entry.IsDir() {
559				continue
560			}
561			count++
562			full := filepath.Join(root, entry.Name())
563			complete := false
564			if primaryFile != "" {
565				if _, err := os.Stat(filepath.Join(full, primaryFile)); err == nil {
566					complete = true
567				}
568			}
569			if !complete && secondaryFile != "" {
570				if _, err := os.Stat(filepath.Join(full, secondaryFile)); err == nil {
571					complete = true
572				}
573			}
574			if complete {
575				summary.CompleteEvidenceDirs++
576				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
577					Path:    filepath.ToSlash(filepath.Join(rootRel, entry.Name())),
578					Class:   "complete_evidence",
579					Message: "complete evidence preserved",
580				})
581			}
582		}
583		return count
584	}
