28	func (f *CommandFactory) newCleanupCommand() *cobra.Command {
29		cmd := &cobra.Command{
30			Use:   "cleanup",
31			Short: "Inspect and clean stale DDx execution resources",
32			Long: `Inspect DDx-owned execution resources and conservatively clean stale state.
33	
34	By default, cleanup runs in dry-run mode and reports what it would remove.
35	Use --apply to remove stale DDx temp worktrees, stale run-state files, and
36	other DDx-owned scratch resources under the configured project roots.
37	
38	Examples:
39	  ddx cleanup
40	  ddx cleanup --json
41	  ddx cleanup --apply
42	  ddx cleanup --project /path/to/project --apply`,
43			Args: cobra.NoArgs,
44			RunE: f.runCleanup,
45		}
46	
