35	func executionWorktreeRootFromFile(path, relativeBase string) string {
36		if strings.TrimSpace(path) == "" {
37			return ""
38		}
39		cfg, err := LoadFromFile(path)
40		if err != nil || cfg == nil || cfg.Executions == nil {
41			return ""
42		}
43		return normalizeExecutionWorktreeRoot(cfg.Executions.TempWorktreeRoot, relativeBase)
44	}
45	
46	func normalizeExecutionWorktreeRoot(path, relativeBase string) string {
47		path = strings.TrimSpace(path)
48		if path == "" {
49			return ""
50		}
51		if path == "~" {
52			if home, err := os.UserHomeDir(); err == nil && home != "" {
53				path = home
54			}
55		} else if strings.HasPrefix(path, "~/") {
56			if home, err := os.UserHomeDir(); err == nil && home != "" {
57				path = filepath.Join(home, strings.TrimPrefix(path, "~/"))
58			}
59		}
60		if !filepath.IsAbs(path) && strings.TrimSpace(relativeBase) != "" {
61			path = filepath.Join(relativeBase, path)
62		}
63		return filepath.Clean(path)
64	}
