// cleanupScratchDirs scans the scratch root for DDx-owned directories whose
// names match an allowlisted prefix, applies age and liveness checks, and
// removes stale ones.
func (m *ExecutionCleanupManager) cleanupScratchDirs(now time.Time, summary *ExecutionCleanupSummary) {
	scratchRoot := m.ScratchRoot
	if scratchRoot == "" {
		scratchRoot = os.TempDir()
	}
	prefixes := m.ScratchPrefixes
	if len(prefixes) == 0 {
		prefixes = DDXScratchCleanupPrefixes
	}
	minAge := m.ScratchMinAge
	if minAge == 0 {
		minAge = DefaultScratchMinAge
	}
	probe := m.Probe
	if probe == nil {
		probe = defaultExecutionCleanupLivenessProbe{}
	}

	entries, err := os.ReadDir(scratchRoot)
	if err != nil {
		return
	}

	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		if !hasDDXScratchPrefix(entry.Name(), prefixes) {
			continue
		}
		path := filepath.Join(scratchRoot, entry.Name())

		info, infoErr := entry.Info()
		if infoErr != nil {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    path,
				Class:   "scratch_stat",
				Message: infoErr.Error(),
			})
			continue
		}

		// Preserve when the directory is younger than the minimum age.
		if now.Sub(info.ModTime()) < minAge {
			summary.PreservedActiveScratchDirs++
			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
				Path:    path,
				Class:   "preserved_scratch_dir",
				Message: "fresh mtime",
			})
			continue
		}

		// Consult liveness metadata when present.
		if meta, metaErr := ReadExecutionCleanupMetadata(path); metaErr == nil {
			if live, reason := probe.IsLive(meta, nil, now); live {
				summary.PreservedActiveScratchDirs++
				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
					Path:    path,
					Class:   "preserved_scratch_dir",
					Message: reason,
				})
				continue
			}
		}

		reclaimedBytes, reclaimedInodes, measureErr := measureTree(path)
		if measureErr != nil {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    path,
				Class:   "scratch_measure_tree",
				Message: measureErr.Error(),
			})
		}
		if !m.DryRun {
			if removeErr := os.RemoveAll(path); removeErr != nil {
				summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
					Path:     path,
					Class:    "scratch_dir_remove",
					Message:  removeErr.Error(),
					Blocking: false,
				})
				continue
			}
		}
		summary.RemovedScratchDirs++
		summary.ScratchBytesReclaimed += reclaimedBytes
		summary.ScratchInodesReclaimed += reclaimedInodes
		summary.BytesReclaimed += reclaimedBytes
		summary.InodesReclaimed += reclaimedInodes
		class := "removed_scratch_dir"
		if m.DryRun {
			class = "would_remove_scratch_dir"
		}
		summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
			Path:    path,
			Class:   class,
			Message: "stale scratch dir",
			Bytes:   reclaimedBytes,
			Inodes:  reclaimedInodes,
		})
	}
}

func hasDDXScratchPrefix(name string, prefixes []string) bool {
	for _, p := range prefixes {
		if strings.HasPrefix(name, p) {
			return true
		}
	}
	return false
}

