func TestExecutionCleanup_RemovesStaleDDXScratchDirs(t *testing.T) {
	projectRoot := setupExecutionCleanupProjectRoot(t)
	tempRoot := t.TempDir()  // exec worktree root (separate)
	scratchRoot := t.TempDir() // DDx scratch root

	// Stale scratch dir with allowlisted prefix.
	staleScratch := filepath.Join(scratchRoot, "ddx-fixture-stale-cleanup-test")
	require.NoError(t, os.MkdirAll(staleScratch, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(staleScratch, "data.txt"), []byte("stale\n"), 0o644))

	// Another stale scratch dir with a different allowlisted prefix.
	staleE2E := filepath.Join(scratchRoot, "ddx-e2e-stale-cleanup-test")
	require.NoError(t, os.MkdirAll(staleE2E, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(staleE2E, "data.txt"), []byte("stale e2e\n"), 0o644))

	// Non-DDx prefix dir — must not be touched.
	otherDir := filepath.Join(scratchRoot, "my-custom-scratch-dir")
	require.NoError(t, os.MkdirAll(otherDir, 0o755))

	mgr := NewExecutionCleanupManager(projectRoot, &executionCleanupTestGitOps{})
	mgr.TempRoot = tempRoot
	mgr.ScratchRoot = scratchRoot
	mgr.ScratchMinAge = 2 * time.Hour
	// Advance Now by 4 h so scratch dirs appear old enough.
	mgr.Now = func() time.Time { return time.Now().Add(4 * time.Hour) }

	summary, err := mgr.Cleanup(context.Background())
	require.NoError(t, err)

	assert.NoDirExists(t, staleScratch, "stale DDx scratch dir should be removed")
	assert.NoDirExists(t, staleE2E, "stale DDx e2e scratch dir should be removed")
	assert.DirExists(t, otherDir, "non-DDx dir must be preserved")
	assert.Equal(t, int64(2), summary.RemovedScratchDirs)
	assert.NotZero(t, summary.ScratchBytesReclaimed)
	assert.NotZero(t, summary.ScratchInodesReclaimed)
	assert.True(t, hasObservationClass(summary.Observations, "removed_scratch_dir"))
}

func TestExecutionCleanup_PreservesActiveDDXScratchDirs(t *testing.T) {
	projectRoot := setupExecutionCleanupProjectRoot(t)
	tempRoot := t.TempDir()
	scratchRoot := t.TempDir()

	// Fresh-mtime scratch dir: current time, ScratchMinAge=2h, Now=default → preserved.
	freshScratch := filepath.Join(scratchRoot, "ddx-e2e-fresh-active")
	require.NoError(t, os.MkdirAll(freshScratch, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(freshScratch, "data.txt"), []byte("fresh\n"), 0o644))

	// Stale-mtime but unexpired liveness scratch dir.
	liveScratch := filepath.Join(scratchRoot, "ddx-test-live-liveness")
	require.NoError(t, os.MkdirAll(liveScratch, 0o755))
	require.NoError(t, WriteExecutionCleanupMetadata(liveScratch, ExecutionCleanupMetadata{
		ProjectRoot:  projectRoot,
		WorktreePath: liveScratch,
		Liveness: &ExecutionCleanupLiveness{
			ExpiresAt: time.Now().Add(1 * time.Hour),
		},
	}))
	// Set the directory's mtime to 3 h ago (after writing the file so Chtimes wins).
	oldTime := time.Now().Add(-3 * time.Hour)
	require.NoError(t, os.Chtimes(liveScratch, oldTime, oldTime))

	// Non-DDx prefix: must be completely ignored.
	nonDDxDir := filepath.Join(scratchRoot, "custom-tool-scratch-dir")
	require.NoError(t, os.MkdirAll(nonDDxDir, 0o755))

	mgr := NewExecutionCleanupManager(projectRoot, &executionCleanupTestGitOps{})
	mgr.TempRoot = tempRoot
	mgr.ScratchRoot = scratchRoot
	mgr.ScratchMinAge = 2 * time.Hour
	// Use default Now and default probe — fresh mtime protects freshScratch;
	// unexpired ExpiresAt protects liveScratch.

	summary, err := mgr.Cleanup(context.Background())
	require.NoError(t, err)

	assert.DirExists(t, freshScratch, "fresh-mtime scratch dir must be preserved")
	assert.DirExists(t, liveScratch, "live-liveness scratch dir must be preserved")
	assert.DirExists(t, nonDDxDir, "non-DDx scratch dir must be ignored")
	assert.Equal(t, int64(0), summary.RemovedScratchDirs)
	assert.Equal(t, int64(2), summary.PreservedActiveScratchDirs)
	assert.True(t, hasObservationClass(summary.Observations, "preserved_scratch_dir"))
}

func TestExecutionCleanup_ReclaimsExpiredTestOwnedWorktrees(t *testing.T) {
	projectRoot := setupExecutionCleanupProjectRoot(t)
	tempRoot := t.TempDir()

	// Worktree whose metadata points to a temp test project root that is now gone.
	fakeProjectRoot := t.TempDir()
	expiredPath := filepath.Join(tempRoot, ExecuteBeadWtPrefix+"ddx-expired-test-deadbeef")
	writeExecutionCleanupCandidate(t, expiredPath, ExecutionCleanupMetadata{
		ProjectRoot:  fakeProjectRoot,
		BeadID:       "ddx-expired",
		AttemptID:    "deadbeef",
		WorktreePath: expiredPath,
	}, map[string]string{"scratch.txt": "expired\n"})
	// Simulate test cleanup by deleting the project root.
	require.NoError(t, os.RemoveAll(fakeProjectRoot))

	// Worktree whose metadata points to an active foreign project (root still exists).
	foreignProjectRoot := t.TempDir()
	foreignPath := filepath.Join(tempRoot, ExecuteBeadWtPrefix+"ddx-foreign-test-feedface")
	writeExecutionCleanupCandidate(t, foreignPath, ExecutionCleanupMetadata{
		ProjectRoot:  foreignProjectRoot,
		BeadID:       "ddx-foreign",
		AttemptID:    "feedface",
		WorktreePath: foreignPath,
	}, map[string]string{"scratch.txt": "foreign\n"})

	mgr := NewExecutionCleanupManager(projectRoot, &executionCleanupTestGitOps{})
	mgr.TempRoot = tempRoot
	// Default probe: neither worktree has preserved/liveness metadata so both
	// read as stale. The foreign one is saved by its project root still existing.

	summary, err := mgr.Cleanup(context.Background())
	require.NoError(t, err)

	assert.NoDirExists(t, expiredPath, "expired test-owned worktree must be reclaimed")
	assert.DirExists(t, foreignPath, "active foreign project worktree must be preserved")
	assert.Equal(t, int64(1), summary.RemovedUnregisteredTempDirs)
	require.NotEmpty(t, summary.Warnings)
	assert.Equal(t, "ownership_mismatch", summary.Warnings[0].Class,
		"foreign project mismatch should produce a warning")
}

